mapper.select:
select oi.orderid, oi.order_data as order_date, ui.name as unit_name, pi.name as product_name, oi.machineid, oi.order_count, oi.product_count, oi.delivery_date, oi.type, oi.remark from order_info oi inner join unit_info ui on ui.userid = #{userid} and ui.unitid = oi.unitid inner join product_info pi on pi.userid = #{userid} and pi.productid = oi.productid
oi.userid = #{userid}
and oi.orderid like CONCAT('%', #{orderid}, '%')
and oi.order_data = #{order_date}
and ui.name like CONCAT('%', #{unit_name}, '%')
and pi.name like CONCAT('%', #{product_name}, '%')
and oi.machineid like CONCAT('%', #{machineid}, '%')
and oi.delivery_date = #{delivery_date}
and oi.type = #{type}
